import React, { useState } from 'react';
import { ChevronDown } from 'lucide-react';

interface FAQItemProps {
  question: string;
  answer: string;
}

const FAQItem: React.FC<FAQItemProps> = ({ question, answer }) => {
  const [isOpen, setIsOpen] = useState(false);

  return (
    <div className="border-b border-white/5 last:border-0">
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className="w-full py-7 flex items-center justify-between text-left hover:bg-white/5 px-4 transition-all duration-300 rounded-lg group"
      >
        <span className="text-lg font-bold pr-8 transition-colors text-white group-hover:text-[#FF7A00]">
          {question}
        </span>
        <div className={`transition-transform duration-500 text-gray-600 ${isOpen ? 'rotate-180 text-[#FF7A00]' : ''}`}>
          <ChevronDown className="w-6 h-6" />
        </div>
      </button>
      <div 
        className={`overflow-hidden transition-all duration-500 ease-in-out ${
          isOpen ? 'max-h-96 opacity-100 py-4' : 'max-h-0 opacity-0'
        }`}
      >
        <p className="text-gray-400 leading-relaxed whitespace-pre-line text-lg font-light px-4">
          {answer}
        </p>
      </div>
    </div>
  );
};

export default FAQItem;

import React, { useState, useEffect } from 'react';

const CountdownTimer: React.FC = () => {
  const [hours, setHours] = useState(1);
  const [minutes, setMinutes] = useState(24);
  const [seconds, setSeconds] = useState(3);

  useEffect(() => {
    const interval = setInterval(() => {
      if (seconds > 0) {
        setSeconds(seconds - 1);
      } else {
        if (minutes > 0) {
          setMinutes(minutes - 1);
          setSeconds(59);
        } else {
          if (hours > 0) {
            setHours(hours - 1);
            setMinutes(59);
            setSeconds(59);
          } else {
            // Loop back for simulated urgency
            setHours(1);
            setMinutes(45);
            setSeconds(0);
          }
        }
      }
    }, 1000);

    return () => clearInterval(interval);
  }, [hours, minutes, seconds]);

  const formatNumber = (num: number) => num.toString().padStart(2, '0');

  return (
    <div className="flex justify-center gap-4 mb-8">
      <TimeUnit value={formatNumber(hours)} label="HORAS" />
      <TimeUnit value={formatNumber(minutes)} label="MIN" />
      <TimeUnit value={formatNumber(seconds)} label="SEG" />
    </div>
  );
};

interface TimeUnitProps {
  value: string;
  label: string;
}

const TimeUnit: React.FC<TimeUnitProps> = ({ value, label }) => (
  <div className="flex flex-col items-center">
    <div className="bg-white/10 backdrop-blur-md border border-white/20 px-4 py-3 rounded-xl min-w-[70px]">
      <span className="text-2xl md:text-3xl font-black text-[#FF7A00] leading-none">
        {value}
      </span>
    </div>
    <span className="text-[10px] font-bold mt-2 text-gray-500 tracking-widest uppercase">
      {label}
    </span>
  </div>
);

export default CountdownTimer;
